<template>
	<view class="">
		<u-navbar :z-index="980" :is-back="true" :custom-back="$util.back" :title="title" v-if="title"></u-navbar>
		<u-parse :html="content"></u-parse>
	</view>
</template>

<script>
	export default {
		data() {
			return {
				title: '',
				url: '',
				name: '',
				content: '',
			}
		},

		onLoad(e) {
			if (e.name == 'userAgreement') {
				this.title = '用户协议'
			} else if (e.name == 'privacy') {
				this.title = '隐私协议'
			}
			this.name = e.name
			this.loadData()
		},

		methods: {
			async loadData() {
				// this.loading = true;
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				// let params = {};
				await this.$u.api.parse({
						name: this.name
					})
					.then(res => {
						this.content = res.content
					}).catch(res => {})

				// this.loading = false;
				uni.hideLoading()

			},


		}
	}
</script>

